export async function loadManagedCaddyStatus(project: ProjectEntry): Promise<ManagedCaddyStatus> {
  const paths = managedCaddyPaths(project.id)
  const installed = isCaddyInstalled()
  const mainConfigExists = existsSync(paths.mainConfigPath)
  const fragmentExists = existsSync(paths.fragmentPath)
  const runningConfigText = installed ? await fetchRunningCaddyConfigText() : null
  const running = runningConfigText !== null

  let usingManagedConfig: boolean | null = null
  if (installed && running && mainConfigExists) {
    const managedConfigText = adaptManagedCaddyConfig(paths.mainConfigPath)
    usingManagedConfig = stableJsonFromText(managedConfigText) === stableJsonFromText(runningConfigText)
  }

  return {
    installed,
    running,
    usingManagedConfig,
    mainConfigPath: paths.mainConfigPath,
    mainConfigExists,
    fragmentPath: paths.fragmentPath,
    fragmentExists,
    port: project.report_port,
    exposure: project.report_exposure,
    reportDir: projectReportDir(project),
    localUrls: localUrlsForProject(project.report_port),
    lanUrls: lanUrlsForProject(project.report_port, project.report_exposure),
  }
}

export function managedCaddyStartCommand(): string {
  const mainConfigPath = managedCaddyPaths('placeholder').mainConfigPath
  return `caddy run --config "${mainConfigPath}" --adapter caddyfile`
}

function managedSiteAddress(reportPort: number, exposure: ProjectEntry['report_exposure']): string {
  if (exposure === 'lan') {
    return `http://:${String(reportPort)}`
  }
  return `http://127.0.0.1:${String(reportPort)}, http://localhost:${String(reportPort)}`
}

function quoteForCaddyPath(value: string): string {
  const normalized = toPosixPath(resolve(value)).replace(/"/g, '\\"')
  return `"${normalized}"`
}

function writeTextIfChanged(path: string, content: string): void {
  if (existsSync(path) && readFileSync(path, 'utf-8') === content) {
    return
  }
  writeFileSync(path, content, 'utf-8')
}

function validateManagedCaddyConfig(mainConfigPath: string): void {
  execCommand('caddy', ['adapt', '--config', mainConfigPath, '--adapter', 'caddyfile', '--validate'], {
    allowFailure: false,
  })
}

function reloadManagedCaddy(mainConfigPath: string): void {
  execCommand('caddy', ['reload', '--config', mainConfigPath, '--adapter', 'caddyfile'])
}

function adaptManagedCaddyConfig(mainConfigPath: string): string {
  return execCommand('caddy', ['adapt', '--config', mainConfigPath, '--adapter', 'caddyfile'])
}

async function fetchRunningCaddyConfigText(): Promise<string | null> {
  try {
    const response = await fetch(`${CADDY_ADMIN_URL}/config/`)
    if (!response.ok) return null
    return await response.text()
  } catch {
    return null
  }
}

/**
 * Report build orchestrator.
 * Generates a self-contained multi-page HTML website in Memory/07_reports/.
 */

import {
  existsSync,
  mkdirSync,
  readdirSync,
  readFileSync,
  writeFileSync,
  appendFileSync,
  rmSync,
} from 'node:fs'
import { basename, dirname, join } from 'node:path'

import type { BuildReportOptions } from '../types/report.js'
import type { ManifestEntry } from '../types/transcript.js'
import { computeStats, extractToolNames, accumulateToolCounts } from './stats.js'
import { renderDashboard } from './render/dashboard.js'
import { renderTranscriptList } from './render/transcript-list.js'
import { renderTranscript } from './render/transcript.js'
import type { RenderedMessage } from './render/transcript.js'
import { renderKnowledge } from './render/knowledge.js'
import { renderGoals } from './render/goals.js'
import { renderTodos } from './render/todos.js'
import { renderArchive } from './render/archive.js'
import { renderProjects } from './render/projects.js'
import { renderGraph } from './render/graph.js'
import { buildSearchIndex, renderSearchPage } from './render/search.js'
import { buildLinkGraph } from './render/links.js'
import { renderRssFeed } from './render/rss.js'
import { getSummary } from './summarize.js'
import type { SummaryOptions } from './summarize.js'
import { getTags } from './tags.js'
import { loadLocale } from './i18n/index.js'
import type { Translations } from './i18n/types.js'
import { getLogger } from '../heartbeat/log.js'

const DEFAULT_MODEL = 'claude-haiku-4-5-20251001'

// ---------------------------------------------------------------------------
// Main entry point
// ---------------------------------------------------------------------------

export async function buildReport(options: BuildReportOptions): Promise<void> {
  const { root, output } = options
  const noAi = options.noAi ?? false
  const model = options.model ?? DEFAULT_MODEL
  const locale = options.locale ?? 'en'
  const ghPagesBranch = options.ghPagesBranch ?? ''
  const cname = options.cname ?? ''
  const webhookUrl = options.webhookUrl ?? ''
  const newSessionIds = options.newSessionIds ?? []
  const reportBaseUrl = options.reportBaseUrl ?? ''

  // Cache lives outside the gitignored output dir so it survives rm -rf
  const cacheDir = join(root, 'Memory', '.report-cache')

  // Load translations
  const t: Translations = loadLocale(locale)

  clearOutputDir(output)

  // Ensure output dirs exist
  mkdirSync(output, { recursive: true })
  mkdirSync(join(output, 'transcripts'), { recursive: true })
  mkdirSync(join(output, 'goals'), { recursive: true })
  mkdirSync(join(output, 'knowledge'), { recursive: true })
  mkdirSync(join(output, 'todos'), { recursive: true })
  mkdirSync(join(output, 'archive'), { recursive: true })
  mkdirSync(join(output, 'projects'), { recursive: true })
  mkdirSync(cacheDir, { recursive: true })

  // Ensure Memory/07_reports is gitignored
  ensureGitignore(root, 'Memory/07_reports/')

  // Load all manifests
  const manifests = loadManifests(root)

  // Build link graph from clean markdown
  const linkGraph = buildLinkGraph(manifests, root)

  // Accumulate tool counts while processing transcripts
  let toolCounts: Record<string, number> = {}

  // Summary options
  const summaryOptions: SummaryOptions = { cacheDir, noAi, model }

  // Process each transcript: parse → summarize → render → write → discard
  const snippets: Record<string, string> = {}
  const summaries: Record<string, string> = {}
  const summaryPromises: Array<Promise<void>> = []

  for (const m of manifests) {
    const messages = parseCleanMarkdownMessages(m, root)

    // Tool events from parsed transcript (try raw path)
    const rawPath = resolveRawPath(m, root)
    if (rawPath && existsSync(rawPath)) {
      try {
        const toolSummaries = extractToolSummariesFromRaw(rawPath, m.client)
        const names = extractToolNames(toolSummaries)
        toolCounts = accumulateToolCounts(toolCounts, names)
      } catch {
        // Skip if raw parsing fails
      }
    }

    // Search snippet from first message text
    const firstMsg = messages[0]
    snippets[m.session_id] = firstMsg ? firstMsg.text.slice(0, 300) : ''

    // Summarize + render (deferred to allow parallel API calls)
    const manifest = m
    const msgs = messages
    summaryPromises.push(
      (async () => {
        try {
        const summary = await getSummary(manifest.raw_sha256, msgs, summaryOptions)
        summaries[manifest.session_id] = summary
        const backlinkIds = linkGraph.backlinks[manifest.session_id] ?? []
        const backlinkManifests = backlinkIds
          .map(id => manifests.find(x => x.session_id === id))
          .filter((x): x is ManifestEntry => x !== undefined)

        const html = renderTranscript(msgs, manifest, summary, backlinkManifests, t, reportBaseUrl)
        const outPath = transcriptOutputPath(output, manifest)
        mkdirSync(dirname(outPath), { recursive: true })
        writeFileSync(outPath, html, 'utf-8')
        } catch (err: unknown) {
          // eslint-disable-next-line no-console
          getLogger().warn(`[build] Failed to render ${manifest.session_id}: ${String(err)}`)
        }
      })(),
    )
  }

  // Wait for all transcript renders (parallel, bounded by semaphore in summarize.ts)
  await Promise.all(summaryPromises)

  // Extract tags in parallel (after summaries are ready)
  const tagOptions = { cacheDir, noAi, model }
  const tags: Record<string, string[]> = {}
  await Promise.all(
    manifests.map(async m => {
      const summary = summaries[m.session_id] ?? ''
      tags[m.session_id] = await getTags(m.raw_sha256, summary, tagOptions)
    }),
  )

  // Compute final stats with accumulated tool counts
  const stats = computeStats(manifests, toolCounts)

  // Load markdown content for various pages
  const goalFiles = loadMarkdownFiles(join(root, 'Memory', '01_goals'))
  const todoFiles = loadMarkdownFiles(join(root, 'Memory', '02_todos'))
  const knowledgeFiles = loadMarkdownFiles(join(root, 'Memory', '04_knowledge'))
  const archiveFiles = loadMarkdownFiles(join(root, 'Memory', '05_archive'))

  // Dashboard
  writeFileSync(join(output, 'index.html'), renderDashboard(stats, manifests, t), 'utf-8')

  // Session list
  writeFileSync(
    join(output, 'transcripts', 'index.html'),
    renderTranscriptList(manifests, t, summaries, tags),
    'utf-8',
  )

  // Goals page
  writeFileSync(
    join(output, 'goals', 'index.html'),
    renderGoals(goalFiles, t),
    'utf-8',
  )

  // Knowledge page
  writeFileSync(
    join(output, 'knowledge', 'index.html'),
    renderKnowledge(knowledgeFiles, t),
    'utf-8',
  )

  // Todos page
  writeFileSync(
    join(output, 'todos', 'index.html'),
    renderTodos(todoFiles, t),
    'utf-8',
  )

  // Archive page
  writeFileSync(
    join(output, 'archive', 'index.html'),
    renderArchive(archiveFiles, t),
    'utf-8',
  )

  // Projects page
  writeFileSync(
    join(output, 'projects', 'index.html'),
    renderProjects(manifests, t),
    'utf-8',
  )

  // Knowledge graph
  writeFileSync(
    join(output, 'graph.html'),
    renderGraph(manifests, knowledgeFiles, linkGraph, t),
    'utf-8',
  )

  // Search
  const searchIndex = buildSearchIndex(manifests, m => snippets[m.session_id] ?? '')
  writeFileSync(join(output, 'search.html'), renderSearchPage(searchIndex, t), 'utf-8')

  // RSS Feed
  writeFileSync(join(output, 'feed.xml'), renderRssFeed(manifests, summaries, reportBaseUrl), 'utf-8')

  // GitHub Pages deployment (non-blocking on failure)
  if (ghPagesBranch) {
    try {
      const { deployGithubPages } = await import('./deploy/github-pages.js')
      await deployGithubPages({ repoRoot: root, outputDir: output, branch: ghPagesBranch, cname })
    } catch {
      // Logged inside deployGithubPages
    }
  } else if (cname) {
    // Write CNAME even without deploy (writeFileSync already imported at top)
    writeFileSync(join(output, 'CNAME'), cname + '\n', 'utf-8')
  }

  // Webhook notification (non-blocking on failure)
  if (webhookUrl) {
    try {
      const { sendWebhook } = await import('./deploy/webhook.js')
      await sendWebhook({
        url: webhookUrl,
        sessionCount: manifests.length,
        newSessionIds,
      })
    } catch {
      // Logged inside sendWebhook
    }
  }
}

// ---------------------------------------------------------------------------
// Manifest loading
// ---------------------------------------------------------------------------

function loadManifests(root: string): ManifestEntry[] {
  const manifestsDir = join(root, 'Memory', '06_transcripts', 'manifests')
  if (!existsSync(manifestsDir)) return []

  const manifests: ManifestEntry[] = []
  loadManifestsRecursive(manifestsDir, manifests)
  return manifests
}

function loadManifestsRecursive(dir: string, out: ManifestEntry[]): void {
  let entries: string[]
  try {
    entries = readdirSync(dir)
  } catch {
    return
  }

  for (const entry of entries) {
    const fullPath = join(dir, entry)
    if (entry.endsWith('.json')) {
      try {
        const raw = readFileSync(fullPath, 'utf-8')
        const parsed: unknown = JSON.parse(raw)
        if (
          parsed !== null &&
          typeof parsed === 'object' &&
          typeof (parsed as Record<string, unknown>)['session_id'] === 'string' &&
          typeof (parsed as Record<string, unknown>)['client'] === 'string'
        ) {
          out.push(parsed as ManifestEntry)
        }
      } catch {
        // Skip malformed manifests
      }
    } else {
      // Recurse into subdirectories
      loadManifestsRecursive(fullPath, out)
    }
  }
}

// ---------------------------------------------------------------------------
// Clean markdown message parsing
// ---------------------------------------------------------------------------

/** Parse messages from a clean markdown file. */
export function parseCleanMarkdownMessages(m: ManifestEntry, root: string): RenderedMessage[] {
  const cleanPath = m.repo_clean_path
    ? join(root, m.repo_clean_path)
    : m.global_clean_path
  if (!cleanPath || !existsSync(cleanPath)) return []

  let content: string
  try {
    content = readFileSync(cleanPath, 'utf-8')
  } catch {
    return []
  }

  return parseMessagesFromMarkdown(content)
}

/** Extract role/timestamp/text from clean markdown format. */
export function parseMessagesFromMarkdown(content: string): RenderedMessage[] {
  const messages: RenderedMessage[] = []

  // Find ## Messages section
  const msgSection = content.indexOf('\n## Messages')
  if (msgSection === -1) return []

  const body = content.slice(msgSection + 12) // after "## Messages\n"

  // Split on ### N. role headers
  const msgRe = /^### \d+\.\s+(\w+)/gm
  let match: RegExpExecArray | null
  const starts: Array<{ index: number; role: string }> = []

  while ((match = msgRe.exec(body)) !== null) {
    starts.push({ index: match.index, role: match[1] ?? 'unknown' })
  }

  for (let i = 0; i < starts.length; i++) {
    const start = starts[i]
    if (!start) continue
    const nextStart = starts[i + 1]
    const chunk = nextStart
      ? body.slice(start.index, nextStart.index)
      : body.slice(start.index)

    const lines = chunk.split('\n')
    // First line is the header, second may be timestamp
    let timestamp = ''
    const textLines: string[] = []
    let pastHeader = false

    for (const line of lines) {
      if (!pastHeader && line.startsWith('### ')) {
        pastHeader = true
        continue
      }
      if (!pastHeader) continue
      const tsMatch = line.match(/^- Timestamp:\s*`([^`]+)`/)
      if (tsMatch && !timestamp) {
        timestamp = tsMatch[1] ?? ''
        continue
      }
      textLines.push(line)
    }

    // Remove leading/trailing blank lines from text
    const text = textLines.join('\n').trim()
    if (text || timestamp) {
      messages.push({ role: start.role, timestamp, text })
    }
  }

  return messages
}

// ---------------------------------------------------------------------------
// Raw transcript tool extraction
// ---------------------------------------------------------------------------

/** Best-effort extraction of tool event summaries from a raw JSONL file. */
function extractToolSummariesFromRaw(rawPath: string, _client: string): string[] {
  const summaries: string[] = []
  let content: string
  try {
    content = readFileSync(rawPath, 'utf-8')
  } catch {
    return []
  }

  for (const line of content.split('\n')) {
    const trimmed = line.trim()
    if (!trimmed) continue
    try {
      const record = JSON.parse(trimmed) as Record<string, unknown>
      // Codex: function_call type
      const type = record['type'] as string | undefined
      if (type === 'function_call' || type === 'custom_tool_call') {
        const name = (record['name'] as string | undefined) ?? type
        summaries.push(name)
        continue
      }
      // Claude: tool_use content blocks
      const payload = record['message'] as Record<string, unknown> | undefined
      const content2 = (payload?.['content'] ?? record['content']) as unknown[] | undefined
      if (Array.isArray(content2)) {
        for (const block of content2) {
          if (
            block !== null &&
            typeof block === 'object' &&
            (block as Record<string, unknown>)['type'] === 'tool_use'
          ) {
            const name = ((block as Record<string, unknown>)['name'] as string | undefined) ?? 'tool_use'
            summaries.push(name)
          }
        }
      }
    } catch {
      // Skip malformed lines
    }
  }

  return summaries
}

// ---------------------------------------------------------------------------
// Output path helpers
// ---------------------------------------------------------------------------

function transcriptOutputPath(output: string, m: ManifestEntry): string {
  const cleanPath = m.repo_clean_path || m.global_clean_path || ''
  const stem = cleanPath ? basename(cleanPath, '.md') : m.session_id
  return join(output, 'transcripts', m.client, `${stem}.html`)
}

function resolveRawPath(m: ManifestEntry, root: string): string | null {
  if (m.repo_raw_path) {
    return join(root, m.repo_raw_path)
  }
  if (m.global_raw_path) {
    return m.global_raw_path
  }
  return null
}

// ---------------------------------------------------------------------------
// Markdown file loader (for goals/knowledge/todos/archive)
// ---------------------------------------------------------------------------

function loadMarkdownFiles(dir: string): Array<{ filename: string; title: string; content: string }> {
  if (!existsSync(dir)) return []

  let entries: string[]
  try {
    entries = readdirSync(dir)
  } catch {
    return []
  }

  return entries
    .filter(e => e.endsWith('.md'))
    .sort()
    .map(filename => {
      const fullPath = join(dir, filename)
      let content = ''
      try {
        content = readFileSync(fullPath, 'utf-8')
      } catch {
        // empty
      }
      const title = extractMarkdownTitle(content) || basename(filename, '.md')
      return { filename, title, content }
    })
}

function clearOutputDir(output: string): void {
  if (!existsSync(output)) return

  let entries: string[]
  try {
    entries = readdirSync(output)
  } catch {
    return
  }

  for (const entry of entries) {
    try {
      rmSync(join(output, entry), { recursive: true, force: true })
    } catch {
      // Best-effort cleanup
    }
  }
}

function extractMarkdownTitle(content: string): string {
  const match = content.match(/^#\s+(.+)$/m)
  return match?.[1]?.trim() ?? ''
}

// ---------------------------------------------------------------------------
// .gitignore management
// ---------------------------------------------------------------------------

export function ensureGitignore(root: string, entry: string): void {
  const gitignorePath = join(root, '.gitignore')
  let existing = ''
  if (existsSync(gitignorePath)) {
    try {
      existing = readFileSync(gitignorePath, 'utf-8')
    } catch {
      return
    }
  }
  // Check if already present (normalize line endings)
  const lines = existing.replace(/\r\n/g, '\n').split('\n')
  if (lines.some(l => l.trim() === entry.trim())) return

  // Append with trailing newline
  const append = existing.endsWith('\n') ? entry + '\n' : '\n' + entry + '\n'
  try {
    appendFileSync(gitignorePath, append, 'utf-8')
  } catch {
    // Best-effort
  }
}

/**
 * MemoryTree heartbeat — single execution, stateless, idempotent.
 * Port of scripts/heartbeat.py
 */

import type { ParsedTranscript } from '../types/transcript.js'
import { discoverSourceFiles, transcriptMatchesRepo } from '../transcript/discover.js'
import { importTranscript, transcriptHasContent } from '../transcript/import.js'
import { parseTranscript } from '../transcript/parse.js'
import { slugify } from '../transcript/common.js'
import { defaultGlobalTranscriptRoot } from '../transcript/discover.js'
import type { Config, ProjectEntry } from './config.js'
import {
  findProjectForPath,
  loadConfig,
  noteProjectHeartbeatRun,
  noteProjectRefreshRun,
  projectDisplayName,
  projectExecutionPath,
  projectIsDue,
  projectRefreshIsDue,
  saveConfig,
} from './config.js'
import { acquireLock, releaseLock } from './lock.js'
import { resetFailureCount, writeAlert, writeAlertWithThreshold } from './alert.js'
import type { LogLevel } from './log.js'
import { getLogger, setupLogging } from './log.js'
import { syncProjectContextToMemory, syncProjectOutputsToDevelopment } from './sync.js'
import {
  ensureBranchUpstream,
  ensureProjectWorktree,
  hasTrackingUpstream,
  isProjectMemoryBranch,
} from './worktree.js'
import { git } from '../utils/exec.js'
import { toPosixPath } from '../utils/path.js'
import { basename, join, resolve } from 'node:path'
import { existsSync } from 'node:fs'

// ---------------------------------------------------------------------------
// Sensitive pattern detection
// ---------------------------------------------------------------------------

const SENSITIVE_PATTERNS: readonly RegExp[] = [
  /(?:api[_-]?key|apikey)\s*[:=]\s*\S+/i,
  /(?:password|passwd|pwd)\s*[:=]\s*\S+/i,
  /(?:secret|token)\s*[:=]\s*\S+/i,
  /(?:sk-|pk_live_|sk_live_|ghp_|gho_|glpat-)\S{10,}/,
  /Bearer\s+\S{20,}/i,
]

const RAW_TRANSCRIPT_PREFIX = 'Memory/06_transcripts/raw/'

// ---------------------------------------------------------------------------
// Main entry point
// ---------------------------------------------------------------------------

export interface HeartbeatRunOptions {
  readonly force?: boolean
  readonly root?: string
}

export async function main(options: HeartbeatRunOptions = {}): Promise<number> {
  const config = loadConfig()
  setupLogging(config.log_level as LogLevel)
  const logger = getLogger()

  if (!acquireLock()) {
    logger.info('Another heartbeat instance is running. Exiting.')
    writeAlert('global', 'lock_held', 'Heartbeat exited: another instance held the lock.')
    return 0
  }

  try {
    return await runHeartbeat(config, options)
  } finally {
    releaseLock()
  }
}

// ---------------------------------------------------------------------------
// Heartbeat orchestration
// ---------------------------------------------------------------------------

export async function runHeartbeat(config: Config, options: HeartbeatRunOptions = {}): Promise<number> {
  const logger = getLogger()
  const targetProject = options.root ? findProjectForPath(config, resolve(options.root)) : null

  if (config.projects.length === 0) {
    logger.info('No projects registered in config.toml. Nothing to do.')
    return 0
  }
  if (options.root && !targetProject) {
    logger.warn(`No registered project matched: ${resolve(options.root)}`)
    return 1
  }

  const projects = targetProject ? [targetProject] : config.projects

  logger.info(`Heartbeat started. ${projects.length} project(s) selected.`)

  let nextConfig = config
  let configChanged = false
  const now = new Date()
  const runTimestamp = now.toISOString()

  for (const entry of projects) {
    const projectName = projectDisplayName(entry)
    const projectPath = resolve(projectExecutionPath(entry))
    const heartbeatDue = options.force === true || projectIsDue(entry, now)
    const refreshDue = options.force === true || projectRefreshIsDue(entry, now)

    if (!heartbeatDue && !refreshDue) {
      logger.debug(`[${projectName}] Not due yet, skipping.`)
      continue
    }

    try {
      const worktree = ensureProjectWorktree(entry)
      if (!existsSync(projectPath)) {
        logger.warn(`Project path does not exist, skipping: ${projectPath}`)
        continue
      }

      if (worktree.created) {
        logger.info(`[${projectName}] Created worktree on branch '${worktree.branch}'.`)
      }

      if (heartbeatDue) {
        const contextSync = syncProjectContextToMemory(entry)
        if (!contextSync.skipped) {
          logger.info(
            `[${projectName}] Synced context to ${worktree.branch} ` +
            `(copied ${contextSync.copied}, deleted ${contextSync.deleted}).`,
          )
        }

        await processProject(config, projectPath, projectName, entry)
        nextConfig = noteProjectHeartbeatRun(nextConfig, entry.id, runTimestamp)
        configChanged = true
      }

      if (heartbeatDue || refreshDue) {
        const outputSync = syncProjectOutputsToDevelopment(entry)
        if (!outputSync.skipped) {
          logger.info(
            `[${projectName}] Synced outputs back to development directory ` +
            `(copied ${outputSync.copied}, deleted ${outputSync.deleted}).`,
          )
        }
        nextConfig = noteProjectRefreshRun(nextConfig, entry.id, runTimestamp)
        configChanged = true
      }
    } catch (err: unknown) {
      logger.exception(`Error processing project: ${projectPath}`, err)
      writeAlertWithThreshold(
        toPosixPath(projectPath),
        'push_failed',
        `Heartbeat error for project: ${basename(projectPath)}`,
      )
    }
  }

  if (configChanged) {
    saveConfig(nextConfig)
  }

  logger.info('Heartbeat finished.')
  return 0
}

// ---------------------------------------------------------------------------
// Per-project processing
// ---------------------------------------------------------------------------

export async function processProject(
  config: Config,
  projectPath: string,
  projectName: string,
  project?: ProjectEntry,
): Promise<void> {
  const logger = getLogger()
  const repoSlug = slugify(projectName, 'project')
  const globalRoot = defaultGlobalTranscriptRoot()
  const branch = currentBranch(projectPath)
  const mirrorToRepo = isDedicatedMemorytreeBranch(branch, project)
  const autoPush = project?.auto_push ?? config.auto_push ?? true
  const generateReport = project?.generate_report ?? config.generate_report ?? false
  const aiSummaryModel = project?.ai_summary_model ?? config.ai_summary_model ?? 'claude-haiku-4-5-20251001'
  const locale = project?.locale ?? config.locale ?? 'en'
  const ghPagesBranch = project?.gh_pages_branch ?? config.gh_pages_branch ?? ''
  const cname = project?.cname ?? config.cname ?? ''
  const webhookUrl = project?.webhook_url ?? config.webhook_url ?? ''
  const reportBaseUrl = project?.report_base_url ?? config.report_base_url ?? ''

  if (!mirrorToRepo) {
    logger.warn(
      `[${projectName}] Current branch '${branch}' is not a dedicated MemoryTree branch. ` +
      'Importing to the global archive only.',
    )
  }

  const discovered = discoverSourceFiles()
  let importedCount = 0

  for (const [client, source] of discovered) {
    let parsed: ParsedTranscript
    try {
      parsed = parseTranscript(client, source)
    } catch {
      logger.debug(`Failed to parse ${source}, skipping.`)
      continue
    }

    if (!transcriptHasContent(parsed)) continue
    if (!transcriptMatchesRepo(parsed, projectPath, repoSlug)) continue

    scanSensitive(parsed, projectPath)

    try {
      await importTranscript(parsed, projectPath, globalRoot, repoSlug, 'not-set', mirrorToRepo)
      importedCount++
    } catch {
      logger.exception(`Failed to import transcript: ${source}`)
    }
  }

  if (importedCount === 0) {
    logger.info(`[${projectName}] No new transcripts to import.`)
    return
  }

  logger.info(`[${projectName}] Imported ${importedCount} transcript(s).`)
  if (mirrorToRepo) {
    gitCommitAndPush({ auto_push: autoPush }, projectPath, projectName, importedCount)
  } else {
    logger.info(`[${projectName}] Skipped repo-local commit/push on branch '${branch}'.`)
  }

  if (generateReport) {
    try {
      const { buildReport } = await import('../report/build.js')
      await buildReport({
        root: projectPath,
        output: join(projectPath, 'Memory', '07_reports'),
        noAi: !process.env['ANTHROPIC_API_KEY'],
        model: aiSummaryModel,
        locale,
        ghPagesBranch,
        cname,
        webhookUrl,
        reportBaseUrl,
      })
      logger.info(`[${projectName}] Report generated.`)
    } catch (err: unknown) {
      logger.warn(`[${projectName}] Report generation failed: ${String(err)}`)
      // Never propagate — report failure must not abort heartbeat cycle
    }
  }
}

// ---------------------------------------------------------------------------
// Sensitive pattern scanning
// ---------------------------------------------------------------------------

export function scanSensitive(parsed: ParsedTranscript, projectPath: string): void {
  const logger = getLogger()
  for (const msg of parsed.messages) {
    for (const pattern of SENSITIVE_PATTERNS) {
      if (pattern.test(msg.text)) {
        logger.warn(
          `Sensitive pattern detected in transcript ${parsed.source_path} (project: ${basename(projectPath)}, role: ${msg.role})`,
        )
        writeAlert(
          toPosixPath(projectPath),
          'sensitive_match',
          `Sensitive pattern in transcript: ${basename(parsed.source_path)}`,
        )
        return
      }
    }
  }
}

// ---------------------------------------------------------------------------
// Git operations
// ---------------------------------------------------------------------------

export function gitCommitAndPush(
  config: Pick<Config, 'auto_push'>,
  projectPath: string,
  projectName: string,
  count: number,
): void {
  const logger = getLogger()

  const changedPaths = changedMemoryPaths(projectPath)
  if (changedPaths.length === 0) {
    logger.info(`[${projectName}] No git changes in Memory/.`)
    return
  }

  const stageablePaths = changedPaths.filter(path => !isRepoRawTranscriptPath(path))
  if (stageablePaths.length === 0) {
    logger.info(`[${projectName}] Only raw transcript mirror changes detected; skipping commit.`)
    return
  }

  git(projectPath, 'add', '--', ...stageablePaths)
  git(projectPath, 'commit', '-m', `memorytree(transcripts): import ${count} transcript(s)`)
  logger.info(`[${projectName}] Committed ${count} transcript import(s).`)

  if (!config.auto_push) {
    logger.info(`[${projectName}] auto_push disabled, skipping push.`)
    return
  }

  const remotes = git(projectPath, 'remote')
  if (!remotes.trim()) {
    logger.warn(`[${projectName}] No git remote configured, skipping push.`)
    writeAlert(toPosixPath(projectPath), 'no_remote', 'Push skipped: no Git remote configured.')
    return
  }

  if (!tryPush(projectPath, projectName)) {
    logger.warn(`[${projectName}] Push failed, retrying once...`)
    if (!tryPush(projectPath, projectName)) {
      logger.error(`[${projectName}] Push failed after retry.`)
      writeAlertWithThreshold(toPosixPath(projectPath), 'push_failed', 'Push failed after retry.')
      return
    }
  }

  resetFailureCount(toPosixPath(projectPath), 'push_failed')
}

export function tryPush(projectPath: string, projectName: string): boolean {
  try {
    const branch = currentBranch(projectPath)
    if (hasTrackingUpstream(projectPath)) {
      git(projectPath, 'push')
    } else {
      const upstream = ensureBranchUpstream(projectPath, branch)
      if (upstream.remote === null) {
        return false
      }
      getLogger().info(`[${projectName}] Configured upstream ${upstream.remote}/${branch}.`)
    }
    getLogger().info(`[${projectName}] Pushed successfully.`)
    return true
  } catch {
    return false
  }
}

export function currentBranch(projectPath: string): string {
  return git(projectPath, 'rev-parse', '--abbrev-ref', 'HEAD').trim()
}

export function isDedicatedMemorytreeBranch(
  branch: string,
  project?: Pick<ProjectEntry, 'memory_branch'>,
): boolean {
  return isProjectMemoryBranch(branch, project)
}

export function changedMemoryPaths(projectPath: string): string[] {
  const status = git(projectPath, 'status', '--porcelain', '--untracked-files=all', '--', 'Memory/')
  const seen = new Set<string>()
  const paths: string[] = []

  for (const rawLine of status.split(/\r?\n/)) {
    const path = statusLinePath(rawLine)
    if (path === null || seen.has(path)) continue
    seen.add(path)
    paths.push(path)
  }

  return paths
}

export function isRepoRawTranscriptPath(path: string): boolean {
  return path.replace(/\\/g, '/').startsWith(RAW_TRANSCRIPT_PREFIX)
}

function statusLinePath(line: string): string | null {
  if (line.length < 4) return null

  const rawPath = line.slice(3).trim()
  if (!rawPath) return null

  const path = rawPath.includes(' -> ')
    ? rawPath.slice(rawPath.lastIndexOf(' -> ') + 4)
    : rawPath

  return unquotePath(path)
}

function unquotePath(path: string): string {
  if (!(path.startsWith('"') && path.endsWith('"'))) return path

  return path
    .slice(1, -1)
    .replace(/\\"/g, '"')
    .replace(/\\\\/g, '\\')
}

// ---------------------------------------------------------------------------

export async function buildReport(options: BuildReportOptions): Promise<void> {
  const { root, output } = options
  const noAi = options.noAi ?? false
  const model = options.model ?? DEFAULT_MODEL
  const locale = options.locale ?? 'en'
  const ghPagesBranch = options.ghPagesBranch ?? ''
  const cname = options.cname ?? ''
  const webhookUrl = options.webhookUrl ?? ''
  const newSessionIds = options.newSessionIds ?? []
  const reportBaseUrl = options.reportBaseUrl ?? ''

  // Cache lives outside the gitignored output dir so it survives rm -rf
  const cacheDir = join(root, 'Memory', '.report-cache')

  // Load translations
  const t: Translations = loadLocale(locale)

  clearOutputDir(output)

  // Ensure output dirs exist
  mkdirSync(output, { recursive: true })
  mkdirSync(join(output, 'transcripts'), { recursive: true })
  mkdirSync(join(output, 'goals'), { recursive: true })
  mkdirSync(join(output, 'knowledge'), { recursive: true })
  mkdirSync(join(output, 'todos'), { recursive: true })
  mkdirSync(join(output, 'archive'), { recursive: true })
  mkdirSync(join(output, 'projects'), { recursive: true })
  mkdirSync(cacheDir, { recursive: true })

  // Ensure Memory/07_reports is gitignored
  ensureGitignore(root, 'Memory/07_reports/')

  // Load all manifests
  const manifests = loadManifests(root)

  // Build link graph from clean markdown
  const linkGraph = buildLinkGraph(manifests, root)

  // Accumulate tool counts while processing transcripts
  let toolCounts: Record<string, number> = {}

  // Summary options
  const summaryOptions: SummaryOptions = { cacheDir, noAi, model }

  // Process each transcript: parse → summarize → render → write → discard
  const snippets: Record<string, string> = {}
  const summaries: Record<string, string> = {}
  const summaryPromises: Array<Promise<void>> = []

  for (const m of manifests) {
    const messages = parseCleanMarkdownMessages(m, root)

    // Tool events from parsed transcript (try raw path)
    const rawPath = resolveRawPath(m, root)
    if (rawPath && existsSync(rawPath)) {
      try {
        const toolSummaries = extractToolSummariesFromRaw(rawPath, m.client)
        const names = extractToolNames(toolSummaries)
        toolCounts = accumulateToolCounts(toolCounts, names)
      } catch {
        // Skip if raw parsing fails
      }
    }

    // Search snippet from first message text
    const firstMsg = messages[0]
    snippets[m.session_id] = firstMsg ? firstMsg.text.slice(0, 300) : ''

    // Summarize + render (deferred to allow parallel API calls)
    const manifest = m
    const msgs = messages
    summaryPromises.push(
      (async () => {
        try {
        const summary = await getSummary(manifest.raw_sha256, msgs, summaryOptions)
        summaries[manifest.session_id] = summary
        const backlinkIds = linkGraph.backlinks[manifest.session_id] ?? []
        const backlinkManifests = backlinkIds
          .map(id => manifests.find(x => x.session_id === id))
          .filter((x): x is ManifestEntry => x !== undefined)

        const html = renderTranscript(msgs, manifest, summary, backlinkManifests, t, reportBaseUrl)
        const outPath = transcriptOutputPath(output, manifest)
        mkdirSync(dirname(outPath), { recursive: true })
        writeFileSync(outPath, html, 'utf-8')
        } catch (err: unknown) {
          // eslint-disable-next-line no-console
          getLogger().warn(`[build] Failed to render ${manifest.session_id}: ${String(err)}`)
        }
      })(),
    )
  }

  // Wait for all transcript renders (parallel, bounded by semaphore in summarize.ts)
  await Promise.all(summaryPromises)

  // Extract tags in parallel (after summaries are ready)
  const tagOptions = { cacheDir, noAi, model }
  const tags: Record<string, string[]> = {}
  await Promise.all(
    manifests.map(async m => {
      const summary = summaries[m.session_id] ?? ''
      tags[m.session_id] = await getTags(m.raw_sha256, summary, tagOptions)
    }),
  )

  // Compute final stats with accumulated tool counts
  const stats = computeStats(manifests, toolCounts)

  // Load markdown content for various pages
  const goalFiles = loadMarkdownFiles(join(root, 'Memory', '01_goals'))
  const todoFiles = loadMarkdownFiles(join(root, 'Memory', '02_todos'))
  const knowledgeFiles = loadMarkdownFiles(join(root, 'Memory', '04_knowledge'))
  const archiveFiles = loadMarkdownFiles(join(root, 'Memory', '05_archive'))

  // Dashboard
  writeFileSync(join(output, 'index.html'), renderDashboard(stats, manifests, t), 'utf-8')

/**
 * CLI adapters for `memorytree report build` and `memorytree report serve`.
 */

import { createServer } from 'node:http'
import { createReadStream, existsSync, statSync } from 'node:fs'
import { extname, join, resolve, sep } from 'node:path'

// ---------------------------------------------------------------------------
// Build command
// ---------------------------------------------------------------------------

export interface CmdReportBuildOptions {
  root: string
  output: string
  noAi: boolean
  model: string
  locale?: string
  reportBaseUrl?: string
}

export async function cmdReportBuild(opts: CmdReportBuildOptions): Promise<number> {
  const { buildReport } = await import('../report/build.js')
  try {
    const buildOptions = {
      root: resolve(opts.root),
      output: resolve(opts.output),
      noAi: opts.noAi,
      model: opts.model,
      ...(opts.locale ? { locale: opts.locale } : {}),
      ...(opts.reportBaseUrl ? { reportBaseUrl: opts.reportBaseUrl } : {}),
    }
    await buildReport(buildOptions)
    console.log(`Report generated at: ${resolve(opts.output)}`)
    console.log(`Open: ${join(resolve(opts.output), 'index.html')}`)
    return 0
  } catch (err: unknown) {
    console.error(`Report build failed: ${String(err)}`)
    return 1
  }
}

// ---------------------------------------------------------------------------
// Serve command
// ---------------------------------------------------------------------------

export interface CmdReportServeOptions {
  dir: string
  port: number
}

export function cmdReportServe(opts: CmdReportServeOptions): number {
  const root = resolve(opts.dir)
  const port = opts.port

  const MIME: Record<string, string> = {
    '.html': 'text/html; charset=utf-8',
    '.css': 'text/css',
    '.js': 'application/javascript',
    '.json': 'application/json',
    '.svg': 'image/svg+xml',
    '.ico': 'image/x-icon',
  }

  const server = createServer((req, res) => {
    let urlPath: string
    try {
      urlPath = decodeURIComponent((req.url ?? '/').split('?')[0] ?? '/')
    } catch {
      res.writeHead(400, { 'Content-Type': 'text/plain' })
      res.end('Bad request')
      return
    }

    let filePath = join(root, urlPath)

    // Containment check: reject paths that escape the serve root
    // Use sep (\ on Windows, / on Unix) so the check works cross-platform.
    if (!filePath.startsWith(root + sep) && filePath !== root) {
      res.writeHead(403, { 'Content-Type': 'text/plain' })
      res.end('Forbidden')
      return
    }

    // Serve index.html for directory requests
    if (existsSync(filePath) && statSync(filePath).isDirectory()) {
      filePath = join(filePath, 'index.html')
    }

    if (!existsSync(filePath)) {
      res.writeHead(404, { 'Content-Type': 'text/plain' })
      res.end('Not found')
      return
    }

    const ext = extname(filePath)
    const contentType = MIME[ext] ?? 'application/octet-stream'
    res.writeHead(200, { 'Content-Type': contentType })
    const stream = createReadStream(filePath)
    stream.on('error', () => { res.destroy() })
    stream.pipe(res)
  })

  server.on('error', (err: NodeJS.ErrnoException) => {
    if (err.code === 'EADDRINUSE') {
      console.error(`Error: port ${port} is already in use.`)
      process.exit(1)
    }
    console.error(`Server error: ${String(err)}`)
    process.exit(1)
  })

  server.listen(port, () => {
    console.log('Temporary local preview server started.')
    console.log('For long-running local access, prefer Caddy hosting this directory.')
    console.log(`Serving ${root}`)
    console.log(`Open: http://localhost:${port}/`)
    console.log('Press Ctrl+C to stop.')
  })

  return 0
}

